export async function generateQuiz(planId: number, objectiveIndex: number): Promise<QuizDTO> {
  return jsonFetch<QuizDTO>(`/api/lesson-plans/${planId}/quizzes`, {
    method: 'POST',
    body: JSON.stringify({ objectiveIndex })
  })
}

interface Explanation {
  explanation: string
  correctIndex: number
}

export async function getExplanation(quizId: number): Promise<Explanation> {
  return jsonFetch(`/api/quizzes/${quizId}/explain`, { method: 'POST', body: '{}' })
}

interface AnswerData {
  correct: boolean
  explanation?: string
}

export async function checkAnswer(quizId: number, learnerIndex: number): Promise<AnswerData> {
  return jsonFetch(`/api/quizzes/${quizId}/check`, {
    method: 'POST',
    body: JSON.stringify({ learnerIndex })
  })
}

export async function getHint(quizId: number, previousGuessIndex: number | null): Promise<{ hint: string }> {
  return jsonFetch(`/api/quizzes/${quizId}/hint`, {
    method: 'POST',
    body: JSON.stringify({ previousGuessIndex })
  })
}

interface Message {
  message: string
}

export async function learnMore(quizId: number, learnerQuestion: string, history: ChatMessage[]): Promise<Message> {
  return jsonFetch(`/api/quizzes/${quizId}/ai-help`, {
    method: 'POST',
    body: JSON.stringify({ learnerQuestion, history })
  })
}

interface Attempts {
  quizId: number
  learnerIndex: number | null
  attempts: number
}

export async function completeAttempt(planId: number, answers: Array<Attempts>): Promise<AttemptSummary> {
  return jsonFetch(`/api/lesson-plans/${planId}/complete`, {
